/** @file hrms-ui.js — UI layer for the HRMS module (employees, attendance, salary, masters) @depends common.js, hrms-logic.js */

// ═══ GUARD / DEPENDENCY CHECK ═════════════════════════════════════════════
if(typeof _sb==='undefined'||typeof DB==='undefined'){
  document.body.innerHTML='<div style="padding:40px;text-align:center;color:#dc2626"><h2>⚠ js/common.js not loaded</h2></div>';
}

// ═══ BOOT / SESSION RESTORE ═════════════════════════════════════════════
if(typeof _APP_TABLES!=='undefined') _APP_TABLES=['users','hrmsEmployees','hrmsCompanies','hrmsCategories','hrmsEmpTypes','hrmsTeams','hrmsDepartments','hrmsSubDepartments','hrmsDesignations','hrmsDayTypes','hrmsPrintFormats','hrmsSettings'];
// hrmsAttendance loaded on-demand per month, not on boot

// ── Boot — no separate login, uses portal session ──
(async function(){
  try{await bootDB();}catch(e){console.error('HRMS boot error:',e);}
  var splash=document.getElementById('dbSplash');
  if(splash) splash.style.display='none';
  // Restore session from portal (cache-based, no RPC needed)
  var su=_sessionGet('kap_session_user')||localStorage.getItem('kap_rm_user');
  var st=_sessionGet('kap_session_token')||localStorage.getItem('kap_rm_token');
  if(su&&st){
    var u=null;
    try{var _cu=localStorage.getItem('kap_current_user');if(_cu)u=JSON.parse(_cu);if(!u||u.name.toLowerCase()!==su.toLowerCase())u=null;}catch(e){u=null;}
    // Prefer the live DB record over the cached one — admin may have
    // updated roles/apps since this session was created.
    var freshU=(DB.users||[]).find(function(x){return x&&x.name&&x.name.toLowerCase()===su.toLowerCase();});
    if(freshU) u=freshU;
    if(u){
      // Role gate — block direct URL access when user has no HRMS role.
      var _isSA=((u.roles||[]).indexOf('Super Admin')>=0)
        ||((u.hrmsRoles||[]).indexOf('Super Admin')>=0);
      if(!_isSA && !((u.hrmsRoles||[]).length)){
        if(typeof notify==='function') notify('⚠ You do not have access to HRMS.',true);
        _navigateTo('index.html');
        return;
      }
      CU=u;_enrichCU();_hrmsLaunch();return;
    }
  }
  // No valid session — redirect to portal login
  setTimeout(function(){_navigateTo('index.html');},2000);
})();

async function _hrmsLaunch(){
  var lp=document.getElementById('loginPage');if(lp)lp.style.display='none';
  document.getElementById('hrmsApp').style.display='block';
  document.getElementById('topbar').style.display='flex';
  document.getElementById('hrmsUserName').textContent=CU.fullName||CU.name;
  // Salary lockdown — pull salary into memory from the RPC-gated table and
  // merge onto DB.hrmsEmployees BEFORE any render so authorized users see
  // numbers and unauthorized users see '—'/0 everywhere. _hrmsSalaryFetchAll
  // sets _hrmsSalaryAccess to 'ok'/'denied' which the UI can read later.
  try{ if(typeof _hrmsSalaryFetchAll==='function') await _hrmsSalaryFetchAll(); }
  catch(e){ console.warn('salary fetch on boot failed:',e.message); }
  // Plant FK — stamp emp.extra.locationId + period.locationId / monthly
  // salaryMonths[mk].locationId for any legacy record that has a plant
  // name but no id yet. In-memory only on boot; new writes persist the
  // id via saveHrmsEmp, and plant renames cascade via _hrmsCascadePlantRename.
  try{ if(typeof _hrmsBackfillLocationIds==='function') _hrmsBackfillLocationIds(); }
  catch(e){ console.warn('plant locationId backfill failed:',e.message); }
  // Topbar avatar — photo if available, otherwise 2-letter initials.
  (function(){
    var av=document.getElementById('hrmsUserAvatar');if(!av) return;
    var dispName=(CU.fullName||CU.name||'?');
    var initials=String(dispName).trim().split(/\s+/).map(function(w){return w[0]||'';}).slice(0,2).join('').toUpperCase()||'?';
    av.title=dispName;
    if(CU.photo) av.innerHTML='<img src="'+CU.photo+'" style="width:100%;height:100%;object-fit:cover">';
    else { av.textContent=initials; }
  })();
  // Disable background polling — HRMS doesn't need live sync
  if(typeof _bgPollTimer!=='undefined'&&_bgPollTimer){clearInterval(_bgPollTimer);_bgPollTimer=null;}
  // Disable auto-refresh views — only manual refresh
  _onRefreshViews=function(){};
  _hrmsLoadPermissions();
  _hrmsEnforcePermissions();
  // All collapsible groups (Day-wise Attendance, Masters, Utilities)
  // start collapsed on every load — the user clicks the arrow to open
  // whichever group they want. The HTML default `display:none` already
  // gives that, but force-collapse here in case a previous session
  // mutated the DOM. Applies to every role.
  (function(){
    var closeGroup=function(groupId,arrowId){
      var g=document.getElementById(groupId);if(g) g.style.display='none';
      var a=document.getElementById(arrowId);if(a) a.textContent='▶';
    };
    closeGroup('hrmsDasNavGroup','hrmsDasNavArrow');
    closeGroup('hrmsMastersGroup','hrmsMastersArrow');
    closeGroup('hrmsUtilsGroup','hrmsUtilsArrow');
  })();
  // Idempotent gender-case repair: 'male' → 'Male' etc. so the dashboard
  // diversity chart doesn't split a single bucket across casings. Runs
  // in the background; only elevated users actually persist the fix.
  setTimeout(function(){try{_hrmsRepairGenderCase();}catch(_){}},800);
  // Same idea for employment type — collapses 'Piece rate' / 'piece rate'
  // / 'piecerate' onto the canonical 'Piece Rate', etc.
  setTimeout(function(){try{_hrmsRepairEmpTypeCase();}catch(_){}},1000);
  // Calendar override scrubber — drops redundant entries (override
  // equals weekday default) and empty records left over from prior
  // testing. Also audits non-default overrides to the console so
  // residual state like the May-4 WO incident is easy to spot.
  setTimeout(function(){try{_hrmsScrubDayTypes();}catch(_){}},1200);
  // NOTE: `_hrmsRepairResignedInactive()` is retained as a manual,
  // console-callable repair, but is no longer fired on every login —
  // the one-time migration has already swept the data, and re-running
  // it on each boot is wasted work.
  renderHrmsDashboard();
  renderHrmsEmployees();
  _hrmsUpdateChangeReqBadge();
  _hrmsUpdateMyApprovalsBadge();
  _hrmsLoadStatutory();
  _hrmsLoadRolls();
  // Build the empCodes-with-records index in the background. Once it
  // resolves, the employee list re-renders so trash icons disappear from
  // rows whose linked attendance/advances/etc. weren't in the boot payload.
  if(typeof _hrmsLoadEmpsWithRecordsIndex==='function') _hrmsLoadEmpsWithRecordsIndex();
  // Strip the HTML-default `class="page active"` on Dashboard before any
  // navigation runs — otherwise a user without page.dashboard access who
  // also can't navigate elsewhere ends up staring at the Dashboard
  // because the active class never got cleared.
  document.querySelectorAll('.page').forEach(function(p){p.classList.remove('active');});
  document.querySelectorAll('.nav-item').forEach(function(n){n.classList.remove('active');});
  // Single landing strategy for every role: walk the page list in
  // priority order and route to the first page the admin has granted.
  // No more role-name-based shortcuts — those quietly bypassed admin's
  // perm settings and made it impossible to revoke a page from a role
  // that had a hardcoded auto-landing. Multi-role users get the same
  // treatment: whichever accessible page sits earliest in the list.
  if(typeof _hrmsHasAccess!=='function'){hrmsGo('pageHrmsDashboard');return;}
  var _firstPage=['pageHrmsDashboard','pageHrmsUtilDailyAtt','pageHrmsPlantwiseAtt','pageHrmsEmpAtt','pageHrmsAttSal','pageHrmsEmployees','pageHrmsMyAtt','pageHrmsMyApprovals','pageHrmsOrgStructure','pageHrmsAttRules','pageHrmsUtilUpdateEmp'];
  var _pagePerms={
    pageHrmsDashboard:'page.dashboard',
    pageHrmsUtilDailyAtt:'page.utilDailyAttSum',
    pageHrmsPlantwiseAtt:'page.plantwiseAtt',
    pageHrmsEmpAtt:'page.empAtt',
    pageHrmsAttSal:'page.attSal',
    pageHrmsEmployees:'page.employees',
    pageHrmsMyAtt:'page.myAttendance',
    pageHrmsMyApprovals:'page.myApprovals',
    pageHrmsOrgStructure:'page.orgStructure',
    pageHrmsAttRules:'page.attRules',
    pageHrmsUtilUpdateEmp:'page.utilUpdateEmp'
  };
  var _startPage=null;
  for(var _pi=0;_pi<_firstPage.length;_pi++){if(_hrmsHasAccess(_pagePerms[_firstPage[_pi]])){_startPage=_firstPage[_pi];break;}}
  if(_startPage){hrmsGo(_startPage);return;}
  // No HRMS access at all — render a friendly empty state in place of any
  // page so the user sees something explanatory instead of a blank shell.
  _hrmsRenderNoAccessShell();
}

// Empty-state shell shown to users whose admin hasn't granted them access
// to any HRMS page. Kept in pageHrmsDashboard's slot so the existing
// layout (sidebar / topbar) remains intact.
function _hrmsRenderNoAccessShell(){
  var dash=document.getElementById('pageHrmsDashboard');
  if(!dash) return;
  dash.innerHTML='<div class="card" style="padding:48px 32px;text-align:center;max-width:560px;margin:48px auto"><div style="font-size:48px;margin-bottom:16px">🔒</div>'+
    '<div style="font-size:18px;font-weight:800;color:var(--text);margin-bottom:8px">No HRMS access yet</div>'+
    '<div style="font-size:13px;color:var(--text2);line-height:1.6">You\'re signed in as <b>'+(CU&&CU.fullName||CU&&CU.name||'')+'</b>, but no HRMS pages have been enabled for your role. Please ask an administrator to grant access via <b>Configure Access</b>.</div></div>';
  dash.classList.add('active');
}

// Sidebar Sign Out — clears session + remember-me state and bounces back to
// the portal so the user can re-authenticate. Mirrors hwmsLogout / vms
// doLogout but lives here so HRMS doesn't depend on portal-ui.js.
function hrmsLogout(){
  try{CU=null;}catch(e){}
  try{_sessionDel('kap_session_user');_sessionDel('kap_session_token');}catch(e){}
  try{
    localStorage.removeItem('kap_rm_user');
    localStorage.removeItem('kap_rm_token');
    localStorage.removeItem('kap_current_user');
    localStorage.removeItem('kap_db_cache');
  }catch(e){}
  try{window.location.href='index.html';}
  catch(e){try{window.location.replace('index.html');}catch(e2){}}
}

async function _hrmsManualRefresh(){
  notify('🔄 Refreshing data…');
  showSpinner('Fetching latest data…');
  try{
    if(_sb&&_sbReady){
      await Promise.all((_APP_TABLES||[]).map(async function(tbl){
        var sbTbl=SB_TABLES[tbl];if(!sbTbl) return;
        var sel=typeof _syncSelect==='function'?_syncSelect(sbTbl):'*';
        var res=await _sb.from(sbTbl).select(sel).limit(10000);
        if(!res.error&&res.data) DB[tbl]=res.data.map(function(r){return _fromRow(tbl,r);}).filter(Boolean);
      }));
      // Public hrms_employees has salary_day=0/salary_month=0 after the
      // lockdown migration. Re-pull salary from the RPC and re-apply so
      // the refresh doesn't blank out salary in memory.
      if(typeof _hrmsSalaryFetchAll==='function'){
        try{ await _hrmsSalaryFetchAll(); }catch(e){ console.warn('salary refresh failed:',e.message); }
      }
    }
    // Per-month attendance + alteration caches are lazy-loaded outside
    // _APP_TABLES. After an ESSL / alteration import they stay stale
    // (browser shows old data until a hard refresh) — clear them so
    // the next read fetches fresh from the server.
    window._hrmsAttCache={};
    window._hrmsAltCache={};
    if(window._hrmsMonthDataCache) window._hrmsMonthDataCache={};
    // Re-load months the user is likely viewing right now (active DAS
    // date + any month tab currently rendered) so the page doesn't
    // sit empty after the cache wipe.
    var _refreshMks={};
    try{
      var di=document.getElementById('hrmsDasHistDate');
      if(di&&di.value){
        var p=String(di.value).split('-');
        if(p.length>=2) _refreshMks[p[0]+'-'+p[1]]=1;
      }
      if(typeof _hrmsAttSalActiveMk==='string'&&_hrmsAttSalActiveMk) _refreshMks[_hrmsAttSalActiveMk]=1;
    }catch(_){}
    if(typeof _hrmsAttFetchMonth==='function'){
      await Promise.all(Object.keys(_refreshMks).map(function(mk){
        return _hrmsAttFetchMonth(mk).catch(function(){return null;});
      }));
    }
    renderHrmsDashboard();
    renderHrmsEmployees();
    _hrmsUpdateChangeReqBadge();
    _hrmsUpdateMyApprovalsBadge();
    // Refresh the page the user is currently looking at so the new
    // numbers flow through without forcing them to navigate away.
    try{
      var pid=document.querySelector('.page.active')&&document.querySelector('.page.active').id;
      if(pid==='pageHrmsUtilDailyAtt'){
        if(typeof _hrmsDasLoadFromHistory==='function') _hrmsDasLoadFromHistory();
        if(typeof _hrmsDasDeptDetailsRender==='function') _hrmsDasDeptDetailsRender();
        if(typeof _hrmsDasTwRender==='function') _hrmsDasTwRender();
      }
      if(pid==='pageHrmsAttSal'&&typeof renderHrmsAttSal==='function') renderHrmsAttSal();
    }catch(_){}
    hideSpinner();
    notify('✅ Data refreshed — '+((DB.hrmsEmployees||[]).length)+' employees loaded');
  }catch(e){hideSpinner();notify('⚠ Refresh failed: '+e.message,true);}
}
