  pageHrmsEmployees:'Employees',
  pageHrmsEmpEdit:'Employees',
  pageHrmsAttSal:'Monthly Attendance & Salary',
  pageHrmsMyAtt:'My Attendance',
  pageHrmsMyApprovals:'My Approvals',
