// Pages whose sidebar entry lives inside a collapsible group. The
// parent label is prepended to the topbar title so the user can see
// the navigation context at a glance.
var _hrmsParentMenu={
  pageHrmsEmployees:'Masters', pageHrmsEmpEdit:'Masters',
  pageHrmsOrgStructure:'Masters', pageHrmsMCompany:'Masters',
  pageHrmsMCategory:'Masters', pageHrmsMEmpType:'Masters',
  pageHrmsMTeam:'Masters', pageHrmsMDept:'Masters',
  pageHrmsMSubDept:'Masters', pageHrmsMDesig:'Masters',
  pageHrmsMRoll:'Masters', pageHrmsMAllocation:'Masters',
  pageHrmsUtilDailyAtt:'Day-wise Attendance',
  pageHrmsPlantwiseAtt:'Day-wise Attendance',
  pageHrmsEmpAtt:'Day-wise Attendance',
  pageHrmsUtilAttConv:'Utilities',
  pageHrmsUtilMonthlyHc:'Utilities',
  pageHrmsUtilUpdateEmp:'Utilities'
};
// Sub-tab labels for pages whose body is an in-page tabset. The active
// sub-tab name is appended to the title so the operator can see which
// sub-view is current straight from the topbar.
var _hrmsSubTabTitles={
  pageHrmsUtilDailyAtt:{
    manpower:'Allocation vs Actual Manpower',
    deptdetails:'Department-wise Attendance',
    teamwise:'Team-wise Attendance Record',
    rolegrouping:'Role Group Setting',
    alloc:'MP Alloc Setting'
  }
};
function _hrmsUpdateTopTitle(){
  var el=document.getElementById('topbarTitle');if(!el) return;
  var pid=(document.querySelector('.page.active')||{}).id||'';
  var base=_hrmsPageTitles[pid]||'';
  var parent=_hrmsParentMenu[pid]||'';
  var suffix='';
  // Append month for month-aware pages
  if(pid==='pageHrmsAttSal'&&_hrmsMonth){
    var p=_hrmsMonth.split('-');
    suffix=' — '+_MONTH_NAMES[+p[1]]+' '+p[0];
  }
  // Day-wise Attendance landing page hosts several sub-tabs — surface
  // the active one in the title so the topbar reflects what the user
  // is actually looking at.
  if(_hrmsSubTabTitles[pid]){
    var subTab=window._hrmsDasActiveTab||'';
    var subName=_hrmsSubTabTitles[pid][subTab];
    if(subName) suffix=' : '+subName+suffix;
  }
  if(!base){el.textContent='HRMS';return;}
  // Suppress the parent prefix when it equals the page's own title —
  // avoids redundant "Day-wise Attendance → Day-wise Attendance" on the
  // section's landing page (and any future page where the entry is the
  // parent itself rather than a true sub-item).
  var prefix=(parent&&parent!==base)?(parent+' → '):'';
  el.textContent='HRMS : '+prefix+base+suffix;
}

// Page → permission key mapping
var _HRMS_PAGE_PERMS={
  pageHrmsDashboard:'page.dashboard',pageHrmsEmployees:'page.employees',pageHrmsAttSal:'page.attSal',
  pageHrmsMyAtt:'page.myAttendance',
  pageHrmsMyApprovals:'page.myApprovals',
  pageHrmsOrgStructure:'page.orgStructure',
  pageHrmsAttRules:'page.attRules',pageHrmsMCompany:'page.masterPlant',pageHrmsMCategory:'page.masterCategory',
  pageHrmsMEmpType:'page.masterEmpType',pageHrmsMTeam:'page.masterTeam',pageHrmsMDept:'page.masterDept',
  pageHrmsMSubDept:'page.masterSubDept',pageHrmsMDesig:'page.masterDesig',pageHrmsMRoll:'page.masterRoll',pageHrmsMAllocation:'page.masterAllocation',
  pageHrmsUtilAttConv:'page.utilAttConv',
  pageHrmsUtilDailyAtt:'page.utilDailyAttSum',
  pageHrmsPlantwiseAtt:'page.plantwiseAtt',
  pageHrmsEmpAtt:'page.empAtt',
  pageHrmsUtilMonthlyHc:'page.utilMonthlyHc',
  pageHrmsUtilUpdateEmp:'page.utilUpdateEmp'
};

function _hrmsEnforcePermissions(){
  var _hide=function(id){var el=document.getElementById(id);if(el) el.style.display='none';};
  var _show=function(id){var el=document.getElementById(id);if(el) el.style.display='';};
  // Helper — flips a nav id based on a permission key. Returns the
  // boolean so callers can roll up child visibility to decide
  // whether to hide the parent group entirely.
  var _setByPerm=function(id,perm){
    var el=document.getElementById(id);if(!el) return false;
    var ok=_hrmsHasAccess(perm);
    el.style.display=ok?'':'none';
    return ok;
  };
  // Top-level (non-grouped) nav items.
  _setByPerm('navDashboard','page.dashboard');
  _setByPerm('navAttSal','page.attSal');
  _setByPerm('navMyAtt','page.myAttendance');
  _setByPerm('navAttRules','page.attRules');
  // My Approvals — sidebar shows when admin has granted either key:
  //   • page.myApprovals      (Own chain access)
  //   • page.myApprovalsOthers (Other users' approvals access)
  // Renderer scopes rows internally per row's own/others routing.
  (function(){
    var el=document.getElementById('navMyApprovals');
    if(!el) return;
    var hasOwn=(typeof _hrmsHasAccess==='function')?_hrmsHasAccess('page.myApprovals'):true;
    var hasOthers=(typeof _hrmsHasAccess==='function')?_hrmsHasAccess('page.myApprovalsOthers'):false;
    el.style.display=(hasOwn||hasOthers)?'':'none';
  })();
  // Masters group — Employees + Org Structure now live here too.
  var anyMasters=false;
  var mastersPerms={
    navEmployees:'page.employees',
    navOrgStructure:'page.orgStructure',
    navMCompany:'page.masterPlant',
    navMCategory:'page.masterCategory',
    navMEmpType:'page.masterEmpType',
    navMTeam:'page.masterTeam',
    navMDept:'page.masterDept',
    navMSubDept:'page.masterSubDept',
    navMDesig:'page.masterDesig',
    navMRoll:'page.masterRoll',
    navMAllocation:'page.masterAllocation'
  };
  Object.keys(mastersPerms).forEach(function(id){
    if(_setByPerm(id,mastersPerms[id])) anyMasters=true;
  });
  // Parent toggle: hide when no child is visible.
  var mastersNav=document.querySelector('[onclick*="_hrmsToggleMasters"]');
  if(mastersNav) mastersNav.style.display=anyMasters?'':'none';
  // If the parent is hidden, collapse the open group too so a residual
  // expanded state doesn't show an empty band.
  if(!anyMasters){_hide('hrmsMastersGroup');}
  // Day-wise Attendance group — sub-items map to per-tab permissions.
  var anyDas=false;
  var dasPerms={
    navDasPlantwise:'page.plantwiseAtt',
    navDasEmpAtt:'page.empAtt',
    navDasManpower:'tab.das.manpower',
    navDasDeptDetails:'tab.das.deptdetails',
    navDasTeamwise:'tab.das.teamwise'
  };
  Object.keys(dasPerms).forEach(function(id){
    if(_setByPerm(id,dasPerms[id])) anyDas=true;
  });
  // The parent label opens the toggle — visible only if at least one
  // sub-item is accessible. The parent has no id, so target its
  // onclick attribute selector.
  var dasNav=document.querySelector('[onclick*="_hrmsToggleDasNav"]');
  if(dasNav) dasNav.style.display=anyDas?'':'none';
  if(!anyDas){_hide('hrmsDasNavGroup');}
  // Utilities group — each sub-item has its own perm; parent shows
  // only when at least one child is visible.
  var anyUtil=false;
  var utilPerms={
    navUtilAttConv:'page.utilAttConv',
    navUtilMonthlyHc:'page.utilMonthlyHc',
    navUtilUpdateEmp:'page.utilUpdateEmp'
  };
  Object.keys(utilPerms).forEach(function(id){
    if(_setByPerm(id,utilPerms[id])) anyUtil=true;
  });
  var utilsNav=document.querySelector('[onclick*="_hrmsToggleUtilities"]');
  if(utilsNav) utilsNav.style.display=(anyUtil&&_hrmsHasAccess('page.utilities'))?'':'none';
  if(!anyUtil||!_hrmsHasAccess('page.utilities')){_hide('hrmsUtilsGroup');}
  // Hide action buttons based on permissions
  var btnPerms={
    btnImportEmployees:'action.importEmployees',
    btnExportEmployees:'action.exportEmployees',
    btnAddEmployee:'action.addEmployee',
    btnAddMonth:'action.addMonth',
    btnSaveLock:'action.saveLock',
    btnUnlock:'action.unlock',
    btnAddPrintFormat:'action.addPrintFormat',
    btnImportSalExcel:'action.bulkSalRevision',
    btnApproveAllAlt:'action.approveAlt'
  };
  Object.keys(btnPerms).forEach(function(btnId){
    var el=document.getElementById(btnId);
    if(el&&!_hrmsHasAccess(btnPerms[btnId])) el.style.display='none';
  });
}

function hrmsGo(pid,opt){
  // V115 — the Plant master colour picker is a position:fixed popup that
  // stays put when the page swaps underneath it. Close it on every
  // navigation so it doesn't leak onto other pages.
  var _stalePop=document.getElementById('hrmsPlantColorPop');
  if(_stalePop) _stalePop.remove();
  // Optional second arg lets the sidebar sub-menu items pre-select a
  // tab inside Daily Attendance Summary (e.g. hrmsGo('pageHrmsUtilDailyAtt','teamwise')).
  if(pid==='pageHrmsUtilDailyAtt'&&typeof opt==='string'&&opt){
    window._hrmsDasInitialTab=opt;
  }
  var permKey=_HRMS_PAGE_PERMS[pid];
  // pageHrmsMyApprovals is open to all signed-in users — internal
  // scoping (chain-routed for non-elevated users, org-wide for
  // SA / HR Manager) limits what each user actually sees.
  if(pid!=='pageHrmsMyApprovals'&&permKey&&!_hrmsHasAccess(permKey)){notify('Access denied',true);return;}
  document.querySelectorAll('.page').forEach(function(p){p.classList.remove('active');});
  document.querySelectorAll('.nav-item').forEach(function(n){n.classList.remove('active');});
  var pg=document.getElementById(pid);if(pg)pg.classList.add('active');
  var navMap={pageHrmsDashboard:'navDashboard',pageHrmsEmployees:'navEmployees',pageHrmsEmpEdit:'navEmployees',pageHrmsAttSal:'navAttSal',pageHrmsMyAtt:'navMyAtt',pageHrmsMyApprovals:'navMyApprovals',pageHrmsOrgStructure:'navOrgStructure',pageHrmsAttRules:'navAttRules',pageHrmsMCompany:'navMCompany',pageHrmsMCategory:'navMCategory',pageHrmsMEmpType:'navMEmpType',pageHrmsMTeam:'navMTeam',pageHrmsMDept:'navMDept',pageHrmsMSubDept:'navMSubDept',pageHrmsMDesig:'navMDesig',pageHrmsMRoll:'navMRoll',pageHrmsMAllocation:'navMAllocation',pageHrmsUtilAttConv:'navUtilAttConv',pageHrmsUtilDailyAtt:'navUtilDailyAtt',pageHrmsPlantwiseAtt:'navDasPlantwise',pageHrmsUtilMonthlyHc:'navUtilMonthlyHc',pageHrmsUtilUpdateEmp:'navUtilUpdateEmp'};
  var nid=navMap[pid];if(nid){var ne=document.getElementById(nid);if(ne)ne.classList.add('active');}
  _hrmsUpdateTopTitle();
  // Re-render the employee list whenever the user lands on the page — the
  // initial boot render may have happened before DB.hrmsEmployees finished
  // loading, which left the table empty until a filter change forced a
  // re-render.
  if(pid==='pageHrmsEmployees') renderHrmsEmployees();
  if(pid==='pageHrmsAttSal'){
    // Find first allowed main tab; honour a preset `_hrmsActiveMainTab`
    // when it's already on an allowed tab (used by the My Approvals
    // redirect to land on Settings → My Approvals directly).
    var _mainTabs=['settings','attendance','salary','payments','esipf','pt','contract'];
    var _mainTabPerms={settings:'tab.settings',attendance:'tab.attendance',salary:'tab.salary',payments:'tab.payments',esipf:'tab.esipf',pt:'tab.pt',contract:'tab.contract'};
    // Default landing: Settings & Data → My Approvals. Falls back to the
    // first permitted main tab if the user can't access settings.
    var _defTab='settings';
    if(!_hrmsHasAccess(_mainTabPerms.settings)){
      for(var _ti=0;_ti<_mainTabs.length;_ti++){if(_hrmsHasAccess(_mainTabPerms[_mainTabs[_ti]])){_defTab=_mainTabs[_ti];break;}}
    }
    if(_hrmsActiveMainTab&&_mainTabPerms[_hrmsActiveMainTab]&&_hrmsHasAccess(_mainTabPerms[_hrmsActiveMainTab])) _defTab=_hrmsActiveMainTab;
    _hrmsActiveMainTab=_defTab;
    var _pendingSubTab=(_defTab==='settings')?_hrmsActiveSettingsTab:null;
    // Default month: keep the user's current selection if set; otherwise
    // land on the OLDEST UNLOCKED month with data — that's the next bit
    // of payroll work pending. Falls back to the most recent month with
    // data (when everything is locked) or today's YYYY-MM (cold start).
    (async function(){
      var _dm=_hrmsMonth;
      if(!_dm){
        try{ await _hrmsAttFetchIndex(); }catch(e){}
        _dm=_hrmsOldestUnlockedMonth();
        var _idx=_hrmsAttMonthIndex||[];
        if(!_dm&&_idx.length) _dm=_idx[0].monthKey; // descending — most recent
        if(!_dm){var _now=new Date();_dm=_now.getFullYear()+'-'+String(_now.getMonth()+1).padStart(2,'0');}
      }
      _hrmsSelectMonth(_dm).then(function(){
        _hrmsMainTab(_defTab);
        if(_pendingSubTab&&typeof _hrmsSettingsSubTab==='function') _hrmsSettingsSubTab(_pendingSubTab);
        _hrmsUpdateTopTitle();
      });
    })();
  }
  if(pid.indexOf('pageHrmsM')===0){
    if(pid==='pageHrmsMRoll') _hrmsRenderRollMaster();
    else if(pid==='pageHrmsMAllocation') _hrmsRenderAllocationMaster();
    else renderHrmsMaster(pid);
  }
  // Keep the Masters group expanded for every page that lives inside
  // it — Employees + Org Structure + Master pages.
  if(pid==='pageHrmsEmployees'||pid==='pageHrmsEmpEdit'||pid==='pageHrmsOrgStructure'||pid.indexOf('pageHrmsM')===0){
    var _mg=document.getElementById('hrmsMastersGroup');
    var _ma=document.getElementById('hrmsMastersArrow');
    if(_mg) _mg.style.display='block';
    if(_ma) _ma.textContent='▼';
  }
  // Expand the Day-wise Attendance sub-menu group when landing on
  // any of its sub-pages (current DAS page, Plant-wise page, Employee
  // Attendance page).
  if(pid==='pageHrmsUtilDailyAtt'||pid==='pageHrmsPlantwiseAtt'||pid==='pageHrmsEmpAtt'){
    var _dg=document.getElementById('hrmsDasNavGroup');if(_dg) _dg.style.display='block';
    var _da=document.getElementById('hrmsDasNavArrow');if(_da) _da.textContent='▼';
  }
  if(pid.indexOf('pageHrmsUtil')===0){
    var _ug=document.getElementById('hrmsUtilsGroup');if(_ug) _ug.style.display='block';
    var _ua=document.getElementById('hrmsUtilsArrow');if(_ua) _ua.textContent='▼';
    if(pid==='pageHrmsUtilAttConv'&&typeof _hrmsAttConvRender==='function') _hrmsAttConvRender();
    if(pid==='pageHrmsUtilDailyAtt'){
      var _di=document.getElementById('hrmsDasHistDate');
      if(_di){
        var _dnow=new Date();
        var _todayIso=_dnow.getFullYear()+'-'+String(_dnow.getMonth()+1).padStart(2,'0')+'-'+String(_dnow.getDate()).padStart(2,'0');
        // Cap the picker so the browser's native UI disables future
        // dates — defence-in-depth alongside the JS clamps in
        // _hrmsDasShiftHistDate / _hrmsDasLoadFromHistory.
        _di.max=_todayIso;
        if(!_di.value) _di.value=_todayIso;
        else if(_di.value>_todayIso) _di.value=_todayIso;
      }
      if(typeof _hrmsDasUpdateDateLabel==='function') _hrmsDasUpdateDateLabel();
      // Tab-revisit freshness — invalidate every month the visible
      // sub-tabs read on this page: the selected date's month plus the
      // rolling 45-day window of months used by Team-wise / Dept-wise
      // MP Details. Removing the entries forces _hrmsAttFetchMonth to
      // re-fetch from Supabase instead of short-circuiting on cache.
      try{
        if(_di&&_di.value){
          var _p=String(_di.value).split('-');
          var _selDate=new Date(+_p[0],+_p[1]-1,+_p[2]);
          var _mksToBust={};
          _mksToBust[_p[0]+'-'+_p[1]]=1;
          for(var _di45=0;_di45<=45;_di45++){
            var _bd=new Date(_selDate);_bd.setDate(_bd.getDate()-_di45);
            var _byy=_bd.getFullYear(),_bmm=String(_bd.getMonth()+1).padStart(2,'0');
            _mksToBust[_byy+'-'+_bmm]=1;
          }
          Object.keys(_mksToBust).forEach(function(mk){
            if(window._hrmsAttCache) delete window._hrmsAttCache[mk];
            if(window._hrmsAltCache) delete window._hrmsAltCache[mk];
          });
        }
      }catch(_){}
      // Auto-load the page for the input's current date so the user
      // sees the full summary on entry — without having to nudge the
      // date control first. Falls back to the empty-state render if the
      // loader isn't available.
      if(typeof _hrmsDasLoadFromHistory==='function'){
        try{_hrmsDasLoadFromHistory();}catch(_){if(typeof _hrmsDasRender==='function') _hrmsDasRender();}
      } else if(typeof _hrmsDasRender==='function') _hrmsDasRender();
      // Sub-menu entry can pre-select a specific tab via
      // window._hrmsDasInitialTab (set by hrmsGo(pid, tab)). Honour
      // the requested tab whenever the user has explicit access to it
      // (e.g. someone with HR Assistant + Contractor Supervisor /
      // Department Head). Otherwise fall back to the scope role's
      // primary tab.
      var _supScope=(typeof _hrmsDasContractorSupScope==='function')?_hrmsDasContractorSupScope():null;
      var _initTab=window._hrmsDasInitialTab||'';
      if(_initTab) window._hrmsDasInitialTab=null;
      var _initTabPerms={manpower:'tab.das.manpower',deptdetails:'tab.das.deptdetails',teamwise:'tab.das.teamwise'};
      var _hasInitAccess=_initTab&&_initTabPerms[_initTab]&&typeof _hrmsHasAccess==='function'&&_hrmsHasAccess(_initTabPerms[_initTab]);
      var _resolvedTab=null;
      if(typeof _hrmsDasSetTab==='function'){
        if(_hasInitAccess){_hrmsDasSetTab(_initTab);_resolvedTab=_initTab;}
        else if(_supScope){_hrmsDasSetTab('teamwise');_resolvedTab='teamwise';}
        else if(_initTab){_hrmsDasSetTab(_initTab);_resolvedTab=_initTab;}
        else if(!window._hrmsDasActiveTab){_hrmsDasSetTab('manpower');_resolvedTab='manpower';}
        else _resolvedTab=window._hrmsDasActiveTab;
      }
      // Highlight matching sidebar sub-item + expand the group.
      var _dasGroup=document.getElementById('hrmsDasNavGroup');
      var _dasArrow=document.getElementById('hrmsDasNavArrow');
      if(_dasGroup) _dasGroup.style.display='block';
      if(_dasArrow) _dasArrow.textContent='▼';
      var _dasNavMap={manpower:'navDasManpower',deptdetails:'navDasDeptDetails',teamwise:'navDasTeamwise'};
      var _subId=_dasNavMap[_resolvedTab];
      if(_subId){var _sn=document.getElementById(_subId);if(_sn) _sn.classList.add('active');}
    }
    if(pid==='pageHrmsUtilMonthlyHc'&&typeof _hrmsMhgInit==='function') _hrmsMhgInit();
    if(pid==='pageHrmsUtilUpdateEmp'&&typeof _hrmsUpdEmpInit==='function') _hrmsUpdEmpInit();
  }
  if(pid==='pageHrmsMyAtt'&&typeof _hrmsMyAttInit==='function') _hrmsMyAttInit();
  // Re-render the Monthly Headcount Graph whenever the user lands on
  // the Dashboard so calendar / data edits made elsewhere flow in.
  if(pid==='pageHrmsDashboard'&&typeof _hrmsMhgRenderCharts==='function'&&_hrmsMhgState){
    try{_hrmsMhgRenderCharts();}catch(_){}
  }
  if(pid==='pageHrmsMyApprovals'&&typeof _hrmsMyApprovalsRender==='function') _hrmsMyApprovalsRender();
  if(pid==='pageHrmsPlantwiseAtt'&&typeof _hrmsPwAttInit==='function') _hrmsPwAttInit();
  if(pid==='pageHrmsEmpAtt'&&typeof _hrmsEmpAttInit==='function') _hrmsEmpAttInit();
  if(pid==='pageHrmsOrgStructure'&&typeof _hrmsOrgRender==='function') _hrmsOrgRender();
  document.querySelector('.sidebar').classList.remove('open');
  document.querySelector('.sidebar-overlay').classList.remove('show');
}

