    var _rowAnyKey=(c.tbl==='hrmsDepartments')?(it.name+'|||'+(it.plant||'')):it.name;
    var _rowAnyCnt=anyCounts[_rowAnyKey]||0;
    var _rowActiveCnt=(c.tbl==='hrmsDepartments'&&byEt&&byEt[_rowAnyKey])?(+byEt[_rowAnyKey].Total||0):_rowAnyCnt;
    h+='<tr>';
