      var hPres=_presOf(hMk);
      var hActive=teamEmps.filter(function(e){var tag=(typeof _hrmsEmpMonthTag==='function')?_hrmsEmpMonthTag(e,hMk):'AC';return tag!=='IA';});
      var sP=0,sNight=0,sA=0,wd=0;
