      s+='<line x1="'+tdx+'" y1="0" x2="'+tdx+'" y2="'+laneH+'" stroke="#ca8a04" stroke-width="1.5"/>';
      s+='<line x1="'+(tdx+_colWT)+'" y1="0" x2="'+(tdx+_colWT)+'" y2="'+laneH+'" stroke="#ca8a04" stroke-width="1.5"/>';
