      return '<rect x="'+(cx-w/2)+'" y="'+(cy-h/2)+'" width="'+w+'" height="'+h+'" rx="8" ry="8" fill="#64748b" stroke="#0f172a" stroke-width="0.3"/>'
        +'<text x="'+cx+'" y="'+iconY+'" text-anchor="middle" font-size="8" fill="#fff">🌙</text>'
