    +'</select><input type="tel" id="hrmsEmpMobile" inputmode="numeric" maxlength="13" placeholder="XXXX XX XXXX" oninput="_hrmsFormatMobile(this)" style="flex:1;min-width:0;font-family:var(--mono)"></div></div></div>'
